```C++
class Test {
 public:
  Test() : msg("Test message.") {
    std::cout << "Test Constructor called:" << this << std::endl;
  }
  ~Test() {
    std::cout << "Test Destructor called." << std::endl;
  }
  std::string get() { return msg.c_str(); };
 private:
  std::string msg;
};

void Function(const char* msg) {
  std::cout << "Function called: " << msg << std::endl;
}

int main(int argc, char **argv) {
  int a = 0;
  std::cout << "Before calling Function:" << &a << std::endl;
  Function(Test().get().c_str());
  int b = 0;
  std::cout << "After calling Function:" << &b << std::endl;
  return 0;
}
```

