Instead of duplicating code, have common routine that takes decomposition + composition as function arguments?

expr_ref seq_rewriter::merge_ac(expr* r1, expr* r2, 
std::function<bool(expr*,expr*&, expr*&)>& decompose,
std::function<expr*(expr*, expr*)>& compose) {
     ptr_vector<expr> sorted;
     expr* a, *b, *c, *d;
     while (true) {
         if (r1 == r2) {
             sorted.push_back(r1);
             break;
         }
         if (test(r1, a, b) && r2->get_id() < a->get_id()) {
             sorted.push_back(r2);
             sorted.push_back(r1);
             break;
         }
         // same for test(r2, c, d) and r1 is smaller than a
         // other cases: test(r1, a, b) and r1 == a
         // !test(r1, a, b) && !test(r2, c, d)
         if (test(r1, a, b) && test(r2, c, d) && a->get_id() < c->get_id()) {
              sorted.push_back(a);
              r1 = b;
              continue;
         
     }

     // walk sorted from back to front and apply "compose"
}

